<template>
  <main class="debug-shell">
    <header><RouterLink to="/admin/features">← Admin</RouterLink><h1>Production debug</h1><p>Staff-only call diagnostics and growth metrics.</p></header>
    <section v-if="!token" class="auth"><h2>Staff access</h2><input v-model="tokenInput" type="password" placeholder="Admin API token" @keyup.enter="signIn"><button @click="signIn">Open dashboard</button></section>
    <template v-else>
      <p v-if="error" class="error">{{ error }}</p>
      <nav class="tabs"><button v-for="item in tabs" :key="item.id" :class="{active:tab===item.id}" @click="selectTab(item.id)">{{ item.label }}</button></nav>
      <section v-if="tab==='health'" class="health"><article v-for="metric in healthCards" :key="metric.label"><span>{{ metric.label }}</span><strong>{{ metric.value }}</strong><small>{{ metric.detail }}</small></article></section>
      <section v-else-if="tab==='growth'" class="growth"><div class="cards"><article><span>Waitlist signups</span><strong>{{ growth.waitlistTotal ?? '—' }}</strong></article><article><span>Demo sessions</span><strong>{{ growth.demoSessions ?? '—' }}</strong><small>{{ growth.demoCompleted ?? 0 }} completed</small></article><article><span>Demo requests</span><strong>{{ growth.demoRequests ?? '—' }}</strong></article><article><span>Sales requests</span><strong>{{ growth.salesRequests ?? '—' }}</strong></article></div><div class="growth-grid"><article><h2>30-day activity</h2><div class="trend" aria-label="30-day signups and demo activity"><div v-for="point in trendPoints" :key="point.day" class="trend-day"><i :style="{height:`${point.waitlistHeight}%`}" title="Waitlist"></i><i class="demo" :style="{height:`${point.demoHeight}%`}" title="Demo"></i></div></div><p class="legend">Blue: waitlist · green: demos</p></article><article><h2>Funnel</h2><div v-for="stage in growth.funnel || []" :key="stage.label" class="funnel"><span>{{ stage.label }}</span><b>{{ stage.count }}</b></div><p class="muted">Visit tracking is not connected to Postgres yet, so visits are intentionally not shown.</p></article><article><h2>Demo languages</h2><div v-for="item in growth.languages || []" :key="item.language" class="funnel"><span>{{ item.language }}</span><b>{{ item.count }}</b></div></article></div></section>
      <section v-else class="workspace">
        <aside><div class="filters"><input v-model="filters.phone_search" :placeholder="tab==='search'?'Search phone, call ID, or transcript':'Phone or call ID'" @keyup.enter="loadCalls"><select v-model="filters.status" @change="loadCalls"><option value="">All statuses</option><option value="completed">Completed</option><option value="failed">Failed</option><option value="in_progress">In progress</option></select><select v-model="filters.provider" @change="loadCalls"><option value="">All providers</option><option value="plivo">Plivo</option><option value="twilio">Twilio</option></select><input v-model="filters.min_latency_ms" type="number" min="0" placeholder="Min latency ms" @keyup.enter="loadCalls"><details class="more-filters"><summary>More filters</summary><input v-model="filters.org_id" placeholder="Organization"><input v-model="filters.deploy_version" placeholder="Deploy version"><input v-model="filters.instance_id" placeholder="Instance ID"><label>From <input v-model="filters.date_from" type="date"></label><label>To <input v-model="filters.date_to" type="date"></label></details><button @click="loadCalls">Filter</button></div><p class="muted">{{ calls.total ?? calls.items?.length ?? 0 }} calls</p><button v-for="call in calls.items || []" :key="call.call_id" class="call-row" :class="{selected:selected?.call.call_id===call.call_id}" @click="loadDetail(call.call_id)"><span><b>{{ call.phone_number_masked || 'Unknown' }}</b><small>{{ call.provider }} · {{ relative(call.started_at) }}</small></span><span><i :class="call.status">{{ call.status }}</i><small>{{ call.total_latency_ms ?? '—' }} ms · {{ call.error_count }} errors</small></span></button></aside>
        <article class="detail" v-if="selected"><header><div><h2>{{ selected.call.call_id }}</h2><p>{{ selected.call.provider }} · {{ selected.call.org_id }} · {{ selected.call.phone_number_masked || 'Unknown phone' }}</p><p>{{ selected.call.trace_id }} · {{ selected.call.deploy_version }} · {{ selected.call.instance_id }}</p></div><button @click="exportEvents">Export JSON</button></header><div class="metrics"><span>Latency <b>{{ selected.call.total_latency_ms ?? '—' }} ms</b></span><span>Turns <b>{{ selected.call.turn_count }}</b></span><span>Errors <b>{{ selected.call.error_count }}</b></span><span>Reconnects <b>{{ reconnects }}</b></span></div><nav class="detail-views" aria-label="Call detail view"><button :class="{active:detailView==='timeline'}" @click="detailView='timeline'">Timeline</button><button :class="{active:detailView==='transcript'}" @click="detailView='transcript'">Transcript</button></nav><template v-if="detailView==='timeline'"><div class="event-filters"><select v-model="eventKind"><option value="">All event types</option><option v-for="kind in eventKinds" :key="kind" :value="kind">{{ kind }}</option></select><select v-model="eventSeverity"><option value="">All severities</option><option value="info">info</option><option value="warning">warning</option><option value="error">error</option></select></div><div class="timeline"><div v-for="item in filteredTimeline" :key="`${item.kind}-${item.id}`" :class="['event',item.kind,item.severity]"><time>{{ time(item.created_at) }}</time><template v-if="item.kind==='transcript'"><b>{{ item.speaker }}</b><p>{{ item.text }}</p></template><template v-else><b>{{ item.event_type }}</b><span>{{ item.latency_ms ? `${item.latency_ms} ms` : '' }}</span><details><summary>{{ item.payload?.message || item.payload?.component || 'View event payload' }}</summary><pre>{{ pretty(item.payload) }}</pre></details></template></div></div></template><section v-else class="transcript-view"><p v-if="!conversationTurns.length" class="muted">No caller or agent transcript turns are available for this call.</p><article v-for="turn in conversationTurns" :key="turn.id" :class="['transcript-turn',turn.speaker]"><header><b>{{ turn.speaker==='caller' ? 'Caller' : 'Agent' }}</b><time>{{ time(turn.created_at) }}</time></header><p>{{ turn.text }}</p></article></section></article>
        <article class="detail empty" v-else>Select a call to inspect its transcript and event trace.</article>
      </section>
    </template>
  </main>
</template>

<script setup>
import { computed, onBeforeUnmount, ref } from 'vue'
import { RouterLink } from 'vue-router'
const localToken=import.meta.env.VITE_LOCAL_ADMIN_MODE==='true'?import.meta.env.VITE_LOCAL_ADMIN_TOKEN:''
const token=ref(localToken||sessionStorage.getItem('woxza_admin_token')||''), tokenInput=ref(''), tab=ref('calls'), error=ref(''), calls=ref({items:[]}), selected=ref(null), health=ref({}), growth=ref({}), detailView=ref('timeline'), eventKind=ref(''), eventSeverity=ref(''), filters=ref({phone_search:'',status:'',provider:'',org_id:'',date_from:'',date_to:'',deploy_version:'',instance_id:'',min_latency_ms:''}); let poll
const tabs=[{id:'calls',label:'Calls'},{id:'errors',label:'Errors'},{id:'health',label:'System health'},{id:'search',label:'Search'},{id:'growth',label:'Growth'}]
const healthCards=computed(()=>[{label:'In-progress calls',value:health.value.inProgressCalls??'—',detail:'current'},{label:'Postgres pool',value:health.value.postgres?.total??'—',detail:`${health.value.postgres?.idle??0} idle · ${health.value.postgres?.waiting??0} waiting`},{label:'Redis',value:health.value.redis?.available?'Online':'Unavailable',detail:health.value.redis?.latencyMs?`${health.value.redis.latencyMs} ms`:'—'},{label:'Queue',value:health.value.queues?.waiting??'—',detail:'waiting jobs'}])
const eventKinds=computed(()=>[...new Set((selected.value?.events||[]).map(event=>event.event_type))])
const filteredTimeline=computed(()=> (selected.value?.timeline||[]).filter(item => item.kind==='transcript' || ((!eventKind.value || item.event_type===eventKind.value) && (!eventSeverity.value || item.severity===eventSeverity.value))))
const conversationTurns=computed(()=> (selected.value?.transcript||[]).filter(turn=>turn.speaker==='caller'||turn.speaker==='agent'))
const reconnects=computed(()=> (selected.value?.events||[]).filter(event=>event.event_type==='gemini_reconnect').length)
const trendPoints=computed(()=>{const entries=[...(growth.value.trends?.waitlist||[]),...(growth.value.trends?.demos||[])], max=Math.max(1,...entries.map(item=>item.count));const byDay=new Map();for(let offset=29;offset>=0;offset--){const day=new Date(Date.now()-offset*86400000).toISOString().slice(0,10);byDay.set(day,{day,waitlist:0,demos:0})}for(const item of growth.value.trends?.waitlist||[])if(byDay.has(item.day))byDay.get(item.day).waitlist=item.count;for(const item of growth.value.trends?.demos||[])if(byDay.has(item.day))byDay.get(item.day).demos=item.count;return [...byDay.values()].map(item=>({...item,waitlistHeight:Math.max(3,item.waitlist/max*100),demoHeight:Math.max(3,item.demos/max*100)}))})
async function api(path){const r=await fetch(path,{headers:{authorization:`Bearer ${token.value}`}});const body=await r.json();if(!r.ok)throw new Error(body.error||'Request failed');return body}
async function loadCalls(){try{error.value='';const params=new URLSearchParams(filters.value); for(const [key,value] of [...params]) if(!value)params.delete(key); calls.value=await api(`/api/admin/debug/${tab.value==='errors'?'errors':tab.value==='search'?'search':'calls'}${tab.value==='search'?`?q=${encodeURIComponent(filters.value.phone_search)}`:`?${params}`}`)}catch(e){error.value=e.message}}
async function loadDetail(id){try{detailView.value='timeline';eventKind.value='';eventSeverity.value='';selected.value=await api(`/api/admin/debug/calls/${encodeURIComponent(id)}`)}catch(e){error.value=e.message}}
async function loadHealth(){try{health.value=await api('/api/admin/debug/health')}catch(e){error.value=e.message}}
async function loadGrowth(){try{growth.value=await api('/api/admin/growth')}catch(e){error.value=e.message}}
async function selectTab(next){tab.value=next; selected.value=null; clearInterval(poll); if(next==='health'){await loadHealth();poll=setInterval(loadHealth,15000)}else if(next==='growth')await loadGrowth();else await loadCalls()}
function signIn(){token.value=tokenInput.value.trim();sessionStorage.setItem('woxza_admin_token',token.value);selectTab('calls')}
function time(value){return new Date(value).toLocaleTimeString()} function relative(value){return new Intl.RelativeTimeFormat('en',{numeric:'auto'}).format(Math.round((new Date(value)-Date.now())/60000),'minute')} function pretty(value){return JSON.stringify(value,null,2)}
function exportEvents(){const blob=new Blob([JSON.stringify(selected.value.events,null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`${selected.value.call.call_id}-events.json`;a.click();URL.revokeObjectURL(url)}
if(token.value) selectTab('calls'); onBeforeUnmount(()=>clearInterval(poll))
</script>

<style scoped>
.debug-shell{max-width:1440px;margin:auto;padding:105px 26px 60px;color:#10213c}.debug-shell h1{font-size:clamp(2.2rem,5vw,4rem);margin:8px 0}.debug-shell p{color:#63728a}.auth,.workspace,.health,.cards,.growth-grid{display:grid;gap:16px}.auth{max-width:420px;padding:24px;border:1px solid #dce3ed;border-radius:16px}.auth input,.filters input,.filters select,.event-filters select{padding:10px;border:1px solid #cbd5e1;border-radius:8px;font:inherit}.tabs{display:flex;gap:8px;flex-wrap:wrap;margin:25px 0 16px}.tabs button,.filters button,.detail header button,.auth button,.detail-views button{border:0;border-radius:8px;padding:10px 14px;background:#edf2f8;color:#10213c;font:inherit;cursor:pointer}.tabs .active,.auth button,.detail-views .active{background:#2563eb;color:#fff}.workspace{grid-template-columns:minmax(300px,32%) 1fr;border:1px solid #dce3ed;border-radius:16px;overflow:hidden;min-height:600px}.workspace aside{padding:14px;border-right:1px solid #dce3ed;overflow:auto}.filters{display:grid;grid-template-columns:1fr 1fr;gap:7px}.filters button,.filters .more-filters{grid-column:1/-1}.more-filters{color:#52637e;font-size:.87rem}.more-filters[open]{display:grid;gap:7px}.more-filters label{display:grid;gap:3px}.call-row{width:100%;display:flex;justify-content:space-between;text-align:left;gap:8px;padding:14px 4px;border:0;border-top:1px solid #edf1f6;background:none;cursor:pointer;color:inherit}.call-row.selected{background:#edf5ff;margin:0 -8px;padding-inline:12px}.call-row span:last-child{text-align:right}.call-row small{display:block;color:#6b7890;margin-top:4px}.call-row i{font-style:normal;font-size:.75rem;font-weight:700}.completed{color:#087443}.failed{color:#b42318}.in_progress{color:#9a5c00}.detail{padding:25px;overflow:auto}.detail>header{display:flex;justify-content:space-between;gap:15px;align-items:start}.detail h2{margin:0;word-break:break-all}.metrics,.cards,.health{grid-template-columns:repeat(4,1fr)}.metrics{display:flex;gap:12px;margin:20px 0}.metrics span,.health article,.cards article,.growth-grid article{padding:16px;border:1px solid #dce3ed;border-radius:12px;background:#fff}.metrics b,.health strong,.cards strong{display:block;font-size:1.55rem;margin-top:5px}.detail-views{display:flex;gap:6px;margin:0 0 14px}.event-filters{display:flex;gap:8px;margin:0 0 14px}.timeline{border-left:2px solid #dce3ed;padding-left:18px}.event{position:relative;padding:12px 0 12px 14px;border-bottom:1px solid #edf1f6}.event:before{content:'';position:absolute;left:-24px;top:17px;width:10px;height:10px;border-radius:50%;background:#2563eb}.event.error:before{background:#d92d20}.event.warning:before{background:#f79009}.event time{color:#718096;font-size:.78rem;margin-right:8px}.event p{margin:7px 0;color:#172b4d}.event details{margin-top:7px}.event pre{max-height:260px;overflow:auto;padding:12px;background:#111827;color:#dce8ff;border-radius:8px;font-size:.78rem}.transcript-view{display:grid;gap:12px}.transcript-turn{max-width:82%;padding:14px 16px;border-radius:14px;background:#edf5ff;border:1px solid #d6e6ff}.transcript-turn.agent{justify-self:end;background:#f1f4f8;border-color:#dce3ed}.transcript-turn header{display:flex;justify-content:space-between;gap:18px;color:#395170;font-size:.8rem}.transcript-turn p{margin:7px 0 0;color:#172b4d;white-space:pre-wrap}.growth-grid{grid-template-columns:repeat(3,1fr);margin-top:16px}.trend{height:150px;display:flex;align-items:end;gap:2px;border-bottom:1px solid #dce3ed}.trend-day{height:100%;flex:1;display:flex;align-items:end;gap:1px}.trend-day i{display:block;flex:1;min-width:2px;background:#2563eb;border-radius:2px 2px 0 0}.trend-day .demo{background:#16a36a}.legend{font-size:.8rem!important}.funnel{display:flex;justify-content:space-between;padding:13px 0;border-bottom:1px solid #edf1f6}.muted{font-size:.85rem!important;color:#718096!important}.error{color:#b42318!important;font-weight:650}@media(max-width:1000px){.growth-grid{grid-template-columns:1fr}}@media(max-width:800px){.debug-shell{padding:92px 14px 40px}.workspace{grid-template-columns:1fr}.workspace aside{border-right:0;border-bottom:1px solid #dce3ed;max-height:400px}.filters{grid-template-columns:1fr}.health,.cards{grid-template-columns:repeat(2,1fr)}.growth-grid{grid-template-columns:1fr}.metrics{flex-wrap:wrap}.transcript-turn{max-width:100%}}
</style>
